import React, { useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import Pagination from '../components/common/Pagination';
import Layout from '../components/layout/Layout';
import api from '../services/api';
import { formatCurrency, formatDate } from '../utils/helpers';

export default function Invoices() {
  const [invoices, setInvoices] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [status, setStatus] = useState('');
  const [from, setFrom] = useState('');
  const [to, setTo] = useState('');
  const [page, setPage] = useState(1);
  const LIMIT = 20;

  const fetchInvoices = useCallback(async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams({ page, limit: LIMIT });
      if (search) params.append('search', search);
      if (status) params.append('status', status);
      if (from) params.append('from', from);
      if (to) params.append('to', to);
      const res = await api.get(`/invoices?${params}`);
      setInvoices(res.data.data);
      setTotal(res.data.total);
    } finally {
      setLoading(false);
    }
  }, [search, status, from, to, page]);

  useEffect(() => { fetchInvoices(); }, [fetchInvoices]);

  const pages = Math.ceil(total / LIMIT);

  return (
    <Layout title="Invoices">
      <div className="filters-bar">
        <input className="form-control" style={{ width: 260 }} placeholder="Search invoice / customer..." value={search} onChange={(e) => { setSearch(e.target.value); setPage(1); }} />
        <select className="form-control" style={{ width: 150 }} value={status} onChange={(e) => { setStatus(e.target.value); setPage(1); }}>
          <option value="">All Status</option>
          <option value="paid">Paid</option>
          <option value="partial">Partial</option>
          <option value="pending">Pending</option>
          <option value="credit">Credit</option>
        </select>
        <input type="date" className="form-control" style={{ width: 160 }} value={from} onChange={(e) => setFrom(e.target.value)} />
        <input type="date" className="form-control" style={{ width: 160 }} value={to} onChange={(e) => setTo(e.target.value)} />
        <Link to="/billing/new" className="btn btn-primary" style={{ marginLeft: 'auto' }}>+ New Invoice</Link>
      </div>

      <div className="card">
        <div className="card-header">
          <span className="card-title">All Invoices ({total})</span>
        </div>
        <div className="table-container">
          {loading ? <div className="loading"><div className="spinner" /></div> : (
            <table>
              <thead>
                <tr>
                  <th>Invoice No</th>
                  <th>Date</th>
                  <th>Customer</th>
                  <th>Mobile</th>
                  <th className="text-right">Grand Total</th>
                  <th className="text-right">Paid</th>
                  <th className="text-right">Due</th>
                  <th>Status</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {invoices.length === 0 && <tr><td colSpan={9} className="text-center" style={{ padding: 30, color: '#9ea3b5' }}>No invoices found</td></tr>}
                {invoices.map((inv) => (
                  <tr key={inv._id}>
                    <td><Link to={`/billing/${inv._id}`} style={{ color: 'var(--primary)', fontWeight: 700 }}>{inv.invoiceNumber}</Link></td>
                    <td>{formatDate(inv.invoiceDate)}</td>
                    <td style={{ fontWeight: 500 }}>{inv.customerName}</td>
                    <td style={{ color: 'var(--text-muted)' }}>{inv.customerMobile}</td>
                    <td className="text-right font-mono">{formatCurrency(inv.grandTotal)}</td>
                    <td className="text-right font-mono" style={{ color: 'var(--success)' }}>{formatCurrency(inv.paidAmount)}</td>
                    <td className="text-right font-mono" style={{ color: inv.dueAmount > 0 ? 'var(--danger)' : 'var(--text-muted)' }}>
                      {formatCurrency(inv.dueAmount)}
                    </td>
                    <td><span className={`badge badge-${inv.paymentStatus === 'paid' ? 'success' : inv.paymentStatus === 'partial' ? 'warning' : 'danger'}`}>{inv.paymentStatus}</span></td>
                    <td><Link to={`/billing/${inv._id}`} className="btn btn-secondary btn-sm">View</Link></td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
        <Pagination page={page} pages={pages} onPage={setPage} />
      </div>
    </Layout>
  );
}
